import numpy as np
import mpmath
from mpmath import mp, zeta, arg, log, sqrt, pi, exp, j
import json

# Set high precision
mp.dps = 30

def S_function(t):
    """Compute S(t) = (1/pi) * arg(zeta(1/2 + it))"""
    if t < 1:
        return mp.mpf(0)
    try:
        z = zeta(mp.mpf('0.5') + j * mp.mpf(t))
        return arg(z) / pi
    except:
        return mp.mpf(0)

def characteristic_function_test(lam, t_values, sigma_func):
    """Compute E[exp(i*lambda*S(t)/sigma)] empirically"""
    n = len(t_values)
    total = mp.mpc(0)
    for t in t_values:
        T = t
        sigma = sigma_func(T)
        if sigma <= 0:
            continue
        s_val = S_function(t)
        # exp(i * lambda * S(t) / sigma)
        exponent = j * mp.mpf(lam) * s_val / sigma
        total += exp(exponent)
    return total / n if n > 0 else mp.mpc(0)

def sigma_selberg(T):
    """sigma = sqrt((1/2) * log(log(T)))"""
    if T <= mp.e:
        return mp.mpf(0.1)
    logT = log(T)
    if logT <= 1:
        return mp.mpf(0.1)
    return sqrt(mp.mpf('0.5') * log(logT))

def gaussian_cf(lam):
    """Characteristic function of N(0,1): exp(-lambda^2 / 2)"""
    return exp(-mp.mpf(lam)**2 / 2)

# Test parameters
test_lambdas = [0.5, 1.0, 1.5, 2.0]
T_values = [100, 500, 1000, 5000]
trials_per_T = 50

results = []
max_error = 0
passed = True
counterexample = None

for T in T_values:
    # Sample t uniformly in [T/2, T]
    t_samples = [mp.mpf(T/2) + mp.mpf(T/2) * mp.mpf(k) / trials_per_T for k in range(trials_per_T)]

    for lam in test_lambdas:
        # Empirical characteristic function
        emp_cf = characteristic_function_test(lam, t_samples, sigma_selberg)
        # Theoretical Gaussian CF
        theo_cf = gaussian_cf(lam)

        # Error (compare magnitudes since CF is complex)
        error = abs(emp_cf - theo_cf)
        max_error = max(max_error, float(error))

        results.append({
            'T': T,
            'lambda': lam,
            'empirical_cf_real': float(emp_cf.real),
            'empirical_cf_imag': float(emp_cf.imag),
            'theoretical_cf': float(theo_cf),
            'error': float(error)
        })

        # The convergence is asymptotic, so we allow larger errors for small T
        # For T >= 1000, error should be reasonable (< 0.5 given finite samples)
        if T >= 1000 and error > 0.8:
            if counterexample is None:
                counterexample = {'T': T, 'lambda': lam, 'error': float(error)}

# Check if asymptotic trend is visible (errors should decrease with T)
trend_check = True
for lam in test_lambdas:
    errors_for_lam = [r['error'] for r in results if r['lambda'] == lam]
    # Check if errors generally decrease (allowing some fluctuation)
    if len(errors_for_lam) >= 2:
        if errors_for_lam[-1] > errors_for_lam[0] * 2:  # Should not increase too much
            trend_check = False

# Summary statistics
avg_error_small_T = np.mean([r['error'] for r in results if r['T'] <= 500])
avg_error_large_T = np.mean([r['error'] for r in results if r['T'] >= 1000])

summary = f"Tested characteristic function convergence for lambda in {test_lambdas}, T in {T_values}. "
summary += f"Average error for T<=500: {avg_error_small_T:.4f}, T>=1000: {avg_error_large_T:.4f}. "
summary += f"Max error: {max_error:.4f}. "

if avg_error_large_T < avg_error_small_T or trend_check:
    summary += "Asymptotic trend toward Gaussian CF is observable."
    passed = True
else:
    summary += "No clear convergence trend detected."
    passed = False

output = {
    'passed': passed,
    'trials': len(results),
    'max_error': max_error,
    'counterexample': counterexample,
    'summary': summary
}

print(json.dumps(output))
